from starlette.exceptions import HTTPException as StarletteHTTPException
from starlette.requests import ClientDisconnect
from starlette.types import ASGIApp, Message, Receive, Scope, Send

MB = 1024 * 1024
MAX_UPLOAD_BYTES = 10 * MB
MAX_REQUEST_BYTES = MAX_UPLOAD_BYTES + MB  # multipart overhead allowance
CHUNK_SIZE = 64 * 1024
MAGIC_READ_BYTES = 512
MAX_ORIGINAL_FILENAME_BYTES = 1024
MAX_IMAGE_PIXELS = 50_000_000
MAX_ANIMATION_FRAMES = 500
MAX_CONCURRENT_UPLOADS = int(os.getenv("MAX_CONCURRENT_UPLOADS", "8"))
MIN_FREE_DISK_BYTES = 20 * MB
TEMP_FILE_TTL_SECONDS = 24 * 60 * 60

UPLOAD_ROOT = Path(os.getenv("UPLOAD_DIR", "./uploaded_images")).resolve()
TMP_ROOT = UPLOAD_ROOT / ".tmp"

