    mime: str
    pillow_format: str


JPEG = ImageKind(".jpg", "image/jpeg", "JPEG")
PNG = ImageKind(".png", "image/png", "PNG")
GIF = ImageKind(".gif", "image/gif", "GIF")
WEBP = ImageKind(".webp", "image/webp", "WEBP")

ALLOWED_MIME_TYPES = {JPEG.mime, PNG.mime, GIF.mime, WEBP.mime}
EXTENSION_TO_MIME = {
    ".jpg": JPEG.mime,
    ".jpeg": JPEG.mime,
    ".png": PNG.mime,
    ".gif": GIF.mime,
    ".webp": WEBP.mime,
}
MIME_ALIASES = {
    "image/jpg": "image/jpeg",
    "image/pjpeg": "image/jpeg",
    "image/x-png": "image/png",
    "application/octet-stream": None,  # common but untrusted; magic bytes decide
}
WINDOWS_RESERVED_NAMES = {
    "CON", "PRN", "AUX", "NUL",
    *(f"COM{i}" for i in range(1, 10)),
    *(f"LPT{i}" for i in range(1, 10)),
}


class UploadRejected(Exception):
    def __init__(
        self,
        status_code: int,
        code: str,
        message: str,
        details: Optional[dict[str, Any]] = None,
    ):
        self.status_code = status_code
        self.code = code
        self.message = message
        self.details = details or {}


class RequestBodyTooLarge(Exception):
