def log_event(level: int, event: str, **fields: Any) -> None:
    safe_fields = {}
    for key, value in fields.items():
        if isinstance(value, str):
            safe_fields[key] = value[:500]
        else:
            safe_fields[key] = value
    logger.log(level, "%s %s", event, json.dumps(safe_fields, ensure_ascii=True, default=str))


def error_payload(code: str, message: str, upload_id: Optional[str] = None, details: Optional[dict] = None) -> dict:
    error = {"code": code, "message": message}
    if upload_id:
        error["upload_id"] = upload_id
    if details:
        error["details"] = details
    return {"ok": False, "error": error}


def json_error(status_code: int, code: str, message: str, upload_id: Optional[str] = None, details: Optional[dict] = None):
    return JSONResponse(status_code=status_code, content=error_payload(code, message, upload_id, details))


async def send_json_asgi(send: Send, status_code: int, payload: dict) -> None:
    body = json.dumps(payload).encode("utf-8")
    await send({
        "type": "http.response.start",
        "status": status_code,
        "headers": [
            (b"content-type", b"application/json"),
            (b"content-length", str(len(body)).encode("ascii")),
        ],
    })
    await send({"type": "http.response.body", "body": body, "more_body": False})


class MaxUploadBodySizeMiddleware:
    """Reject oversized bodies before multipart parsing consumes temp disk/memory."""

    def __init__(self, app: ASGIApp, max_body_size: int, path: str):
        self.app = app
        self.max_body_size = max_body_size
        self.path = path

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        if scope["type"] != "http" or scope.get("path") != self.path or scope.get("method") != "POST":
            await self.app(scope, receive, send)
            return

        upload_id = uuid.uuid4().hex
        scope.setdefault("state", {})["upload_id"] = upload_id
        client = scope.get("client") or ("unknown", None)
        headers = {k.lower(): v for k, v in scope.get("headers", [])}
        raw_length = headers.get(b"content-length")

        if raw_length:
            try:
                content_length = int(raw_length)
            except ValueError:
                log_event(logging.WARNING, "upload_failed", upload_id=upload_id, code="invalid_content_length")
                await send_json_asgi(send, 400, error_payload("invalid_content_length", "Invalid Content-Length header.", upload_id))
                return

            if content_length > self.max_body_size:
                log_event(logging.INFO, "upload_attempt", upload_id=upload_id, client_ip=client[0], content_length=content_length)
                log_event(logging.WARNING, "upload_failed", upload_id=upload_id, code="request_too_large")
                await send_json_asgi(send, 413, error_payload("request_too_large", "Request body is too large.", upload_id))
                return

        received = 0
        response_started = False

        async def limited_receive() -> Message:
            nonlocal received
            message = await receive()
            if message["type"] == "http.request":
                received += len(message.get("body", b""))
                if received > self.max_body_size:
                    raise RequestBodyTooLarge()
            return message

        async def wrapped_send(message: Message) -> None:
            nonlocal response_started
            if message["type"] == "http.response.start":
                response_started = True
            await send(message)

        try:
            await self.app(scope, limited_receive, wrapped_send)
        except RequestBodyTooLarge:
            log_event(logging.WARNING, "upload_failed", upload_id=upload_id, client_ip=client[0], code="request_too_large_stream")
            if not response_started:
                await send_json_asgi(send, 413, error_payload("request_too_large", "Request body is too large.", upload_id))


def ensure_storage_ready() -> None:
    """Handle missing dirs, permission problems, symlink surprises, and low disk."""
    UPLOAD_ROOT.mkdir(parents=True, exist_ok=True, mode=0o750)
    TMP_ROOT.mkdir(parents=True, exist_ok=True, mode=0o750)

    if UPLOAD_ROOT.is_symlink() or TMP_ROOT.is_symlink():
        raise RuntimeError("Upload directories must not be symlinks.")
    if not UPLOAD_ROOT.is_dir() or not TMP_ROOT.is_dir():
        raise RuntimeError("Upload storage path is not a directory.")
    if not os.access(UPLOAD_ROOT, os.W_OK | os.X_OK) or not os.access(TMP_ROOT, os.W_OK | os.X_OK):
        raise RuntimeError("Upload storage is not writable.")

    ensure_free_space(MAX_UPLOAD_BYTES)


def ensure_free_space(incoming_bytes: int) -> None:
    free = shutil.disk_usage(UPLOAD_ROOT).free
    if free < incoming_bytes + MIN_FREE_DISK_BYTES:
        raise UploadRejected(500, "storage_full", "Insufficient server storage for this upload.")


def cleanup_stale_temp_files() -> None:
    """Cleans temp files left by crashes/restarts mid-upload."""
    now = time.time()
    for path in TMP_ROOT.glob("*.part"):
        with suppress(OSError):
            if path.is_file() and now - path.stat().st_mtime > TEMP_FILE_TTL_SECONDS:
                path.unlink()


def detect_image_kind(data: bytes) -> Optional[ImageKind]:
    # Magic bytes are authoritative; extension and Content-Type are only hints.
    if data.startswith(b"\xff\xd8\xff"):
        return JPEG
    if data.startswith(b"\x89PNG\r\n\x1a\n"):
        return PNG
    if data.startswith((b"GIF87a", b"GIF89a")):
        return GIF
    if len(data) >= 12 and data[0:4] == b"RIFF" and data[8:12] == b"WEBP":
        return WEBP
    return None


def normalize_content_type(content_type: Optional[str]) -> Optional[str]:
    if not content_type:
        return None
    value = content_type.split(";", 1)[0].strip().lower()
    return MIME_ALIASES.get(value, value)


def original_extension(filename: str) -> str:
    base = filename.replace("\\", "/").rsplit("/", 1)[-1]
    return Path(base).suffix.lower()


def sanitize_filename(filename: str) -> str:
    # Defuses path traversal, control chars, Unicode tricks, hidden names, device names.
    name = unicodedata.normalize("NFKC", filename)
    name = name.replace("\\", "/").rsplit("/", 1)[-1]
    name = "".join(ch for ch in name if ch.isprintable() and ch not in "\x00\r\n\t")
    name = name.strip().strip(".")
    name = re.sub(r"\s+", "_", name)
    name = re.sub(r"[^A-Za-z0-9._-]", "_", name)
    while ".." in name:
        name = name.replace("..", ".")
    stem = Path(name).stem[:100].strip("._-") or "upload"
    if stem.upper() in WINDOWS_RESERVED_NAMES:
        stem = f"_{stem}"
    return stem


def validate_declared_types(content_type: Optional[str], ext: str, kind: ImageKind) -> None:
    declared = normalize_content_type(content_type)
    if declared is not None:
        if declared not in ALLOWED_MIME_TYPES:
            raise UploadRejected(415, "unsupported_content_type", "Unsupported file Content-Type.", {"content_type": declared})
        if declared != kind.mime:
            raise UploadRejected(415, "content_type_mismatch", "Content-Type does not match file content.")

    if ext:
        expected = EXTENSION_TO_MIME.get(ext)
        if expected is None:
            raise UploadRejected(400, "unsupported_file_extension", "Filename extension is not allowed.", {"extension": ext})
        if expected != kind.mime:
            raise UploadRejected(415, "extension_type_mismatch", "Filename extension does not match file content.")


def create_temp_file(upload_id: str) -> tuple[Path, int]:
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW

    for _ in range(10):
        path = TMP_ROOT / f"{upload_id}_{uuid.uuid4().hex}.part"
        try:
            return path, os.open(path, flags, 0o600)
        except FileExistsError:
            continue
    raise OSError(errno.EEXIST, "Could not allocate unique temporary file.")


def write_all(fd: int, data: bytes) -> None:
    # Handles partial writes and EINTR explicitly.
    view = memoryview(data)
    while view:
        try:
            written = os.write(fd, view)
        except InterruptedError:
            continue
        if written == 0:
            raise OSError(errno.EIO, "Short write while storing upload.")
        view = view[written:]


def fsync_dir(path: Path) -> None:
    with suppress(OSError):
        fd = os.open(path, os.O_RDONLY)
        try:
            os.fsync(fd)
        finally:
            os.close(fd)


def validate_image_payload(path: Path, expected: ImageKind) -> dict[str, int]:
    # Catches corrupt/truncated images and decompression bombs after bytes are on disk.
    try:
        with warnings.catch_warnings():
            warnings.simplefilter("error", Image.DecompressionBombWarning)
            with Image.open(path) as img:
                if img.format != expected.pillow_format:
                    raise UploadRejected(415, "image_format_mismatch", "Decoded image format does not match magic bytes.")
                width, height = img.size
                frames = getattr(img, "n_frames", 1)
                if width <= 0 or height <= 0:
                    raise UploadRejected(400, "invalid_image_dimensions", "Image has invalid dimensions.")
                if frames > MAX_ANIMATION_FRAMES:
                    raise UploadRejected(413, "too_many_frames", "Animated image has too many frames.")
                img.verify()
                return {"width": width, "height": height, "frames": frames}
    except Image.DecompressionBombError as exc:
        raise UploadRejected(413, "image_too_large_pixels", "Image dimensions are too large.") from exc
    except Image.DecompressionBombWarning as exc:
        raise UploadRejected(413, "image_too_large_pixels", "Image dimensions are too large.") from exc
    except (UnidentifiedImageError, OSError, SyntaxError) as exc:
        raise UploadRejected(415, "invalid_image", "File content is not a valid supported image.") from exc


def make_final_path(stem: str, kind: ImageKind) -> Path:
    for _ in range(10):
        path = UPLOAD_ROOT / f"{uuid.uuid4().hex}_{stem}{kind.ext}"
        path.relative_to(UPLOAD_ROOT)
        if not path.exists():
            return path
    raise OSError(errno.EEXIST, "Could not allocate unique destination filename.")


def map_os_error(exc: OSError) -> tuple[str, str]:
    if exc.errno in {errno.ENOSPC, getattr(errno, "EDQUOT", errno.ENOSPC)}:
        return "storage_full", "Server storage is full."
    if exc.errno in {errno.EACCES, errno.EPERM}:
        return "storage_permission_denied", "Server cannot write to upload storage."
    if exc.errno in {errno.EMFILE, errno.ENFILE}:
        return "storage_resource_exhausted", "Server file descriptor limit was reached."
    return "storage_error", "Server failed while storing the upload."


@asynccontextmanager
async def lifespan(app: FastAPI):
    ensure_storage_ready()
    cleanup_stale_temp_files()
    yield


app = FastAPI(lifespan=lifespan)
app.add_middleware(MaxUploadBodySizeMiddleware, max_body_size=MAX_REQUEST_BYTES, path="/api/upload")


@app.exception_handler(RequestValidationError)
async def validation_error_handler(request: Request, exc: RequestValidationError):
    upload_id = getattr(request.state, "upload_id", uuid.uuid4().hex)
    log_event(logging.WARNING, "upload_failed", upload_id=upload_id, code="invalid_request")
    return json_error(400, "invalid_request", "Expected multipart/form-data with exactly one file field named 'file'.", upload_id)


@app.exception_handler(StarletteHTTPException)
async def http_error_handler(request: Request, exc: StarletteHTTPException):
    upload_id = getattr(request.state, "upload_id", uuid.uuid4().hex)
    code = "malformed_multipart" if exc.status_code == 400 else "request_error"
    status = exc.status_code if exc.status_code in {400, 413, 415} else 500
    log_event(logging.WARNING, "upload_failed", upload_id=upload_id, code=code, status=status)
    return json_error(status, code, "Upload request could not be processed.", upload_id)


@app.post("/api/upload", status_code=201)
async def upload_image(request: Request, file: Optional[list[UploadFile]] = File(default=None)):
    upload_id = getattr(request.state, "upload_id", uuid.uuid4().hex)
    client_ip = request.client.host if request.client else "unknown"
    started = time.monotonic()

    tmp_path: Optional[Path] = None
    final_path: Optional[Path] = None
    fd: Optional[int] = None
    upload: Optional[UploadFile] = None
    acquired = False

    log_event(
        logging.INFO,
        "upload_attempt",
        upload_id=upload_id,
        client_ip=client_ip,
        content_length=request.headers.get("content-length"),
        user_agent=request.headers.get("user-agent"),
    )

    try:
        # Concurrency guard: prevents too many simultaneous disk writers.
        try:
            await asyncio.wait_for(upload_slots.acquire(), timeout=0.25)
            acquired = True
        except asyncio.TimeoutError as exc:
            raise UploadRejected(429, "too_many_uploads", "Too many uploads are in progress; retry later.") from exc

        if not file:
            raise UploadRejected(400, "missing_file", "Missing file field named 'file'.")
        if len(file) != 1:
            raise UploadRejected(400, "too_many_files", "Upload exactly one file.")

        upload = file[0]
        if not upload.filename:
            raise UploadRejected(400, "missing_filename", "Uploaded file must include a filename.")
        if "\x00" in upload.filename:
            raise UploadRejected(400, "invalid_filename", "Filename contains a NUL byte.")
        if len(upload.filename.encode("utf-8", "ignore")) > MAX_ORIGINAL_FILENAME_BYTES:
            raise UploadRejected(400, "filename_too_long", "Filename is too long.")

        safe_stem = sanitize_filename(upload.filename)
        ext = original_extension(upload.filename)

        # Read only a small prefix for magic-byte detection, then stream the rest.
        first = await upload.read(MAGIC_READ_BYTES)
        if not first:
            raise UploadRejected(400, "empty_file", "Uploaded file is empty.")

        kind = detect_image_kind(first)
        if kind is None:
            raise UploadRejected(415, "unsupported_media_type", "Only JPEG, PNG, GIF, and WebP images are allowed.")

        validate_declared_types(upload.content_type, ext, kind)
        ensure_free_space(MAX_UPLOAD_BYTES)

        tmp_path, fd = create_temp_file(upload_id)
        digest = hashlib.sha256()
        total = 0

        def count_or_reject(chunk: bytes) -> None:
            nonlocal total
            total += len(chunk)
            if total > MAX_UPLOAD_BYTES:
                raise UploadRejected(413, "file_too_large", "Uploaded image exceeds the 10MB limit.")

        count_or_reject(first)
        digest.update(first)
        await asyncio.to_thread(write_all, fd, first)

        while True:
            chunk = await upload.read(CHUNK_SIZE)
            if not chunk:
                break

            count_or_reject(chunk)
            digest.update(chunk)

            # Disk-full during upload is caught by os.write; this early check gives a cleaner failure.
            if total % MB < CHUNK_SIZE:
                ensure_free_space(CHUNK_SIZE)

            await asyncio.to_thread(write_all, fd, chunk)

        await asyncio.to_thread(os.fsync, fd)
        os.close(fd)
        fd = None

        image_info = await asyncio.to_thread(validate_image_payload, tmp_path, kind)

        # Atomic publish: temp file is fully written, fsynced, validated, then renamed.
        final_path = make_final_path(safe_stem, kind)
        await asyncio.to_thread(os.replace, tmp_path, final_path)
        tmp_path = None
        await asyncio.to_thread(fsync_dir, UPLOAD_ROOT)

        elapsed_ms = int((time.monotonic() - started) * 1000)
        log_event(
            logging.INFO,
            "upload_success",
            upload_id=upload_id,
            client_ip=client_ip,
            filename=final_path.name,
            original_filename=upload.filename,
            size_bytes=total,
            content_type=kind.mime,
            sha256=digest.hexdigest(),
            elapsed_ms=elapsed_ms,
        )

        return JSONResponse(
            status_code=201,
            content={
                "ok": True,
                "upload_id": upload_id,
                "filename": final_path.name,
                "content_type": kind.mime,
                "size_bytes": total,
                "sha256": digest.hexdigest(),
                **image_info,
            },
        )

    except ClientDisconnect:
        log_event(logging.WARNING, "upload_failed", upload_id=upload_id, client_ip=client_ip, code="client_disconnected")
        return json_error(400, "client_disconnected", "Client disconnected before upload completed.", upload_id)

    except UploadRejected as exc:
        log_event(logging.WARNING, "upload_failed", upload_id=upload_id, client_ip=client_ip, code=exc.code, details=exc.details)
        return json_error(exc.status_code, exc.code, exc.message, upload_id, exc.details)

    except OSError as exc:
        code, message = map_os_error(exc)
        log_event(logging.ERROR, "upload_failed", upload_id=upload_id, client_ip=client_ip, code=code, errno=exc.errno)
        return json_error(500, code, message, upload_id)

    except asyncio.CancelledError:
        log_event(logging.WARNING, "upload_cancelled", upload_id=upload_id, client_ip=client_ip)
        raise

    except Exception as exc:
        log_event(logging.ERROR, "upload_failed", upload_id=upload_id, client_ip=client_ip, code="internal_error", error=repr(exc))
        return json_error(500, "internal_error", "Unexpected server error while processing upload.", upload_id)

    finally:
        if fd is not None:
            with suppress(OSError):
                os.close(fd)
        if tmp_path is not None:
            with suppress(OSError):
                tmp_path.unlink()
        if upload is not None:
            with suppress(Exception):
                await upload.close()
        if acquired:
            upload_slots.release()


